import{_ as e,o as t,c as r,a2 as i}from"./chunks/framework.ZhLefgN8.js";const u=JSON.parse('{"title":"平台隐私政策","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"compliance-and-tax/privacy-policy.md","filePath":"zh-CN/compliance-and-tax/privacy-policy.md"}'),o={name:"compliance-and-tax/privacy-policy.md"};function l(p,a,n,c,h,d){return t(),r("div",null,[...a[0]||(a[0]=[i('<h1 id="平台隐私政策" tabindex="-1">平台隐私政策 <a class="header-anchor" href="#平台隐私政策" aria-label="Permalink to &quot;平台隐私政策&quot;">​</a></h1><p>长桥个人信息收集范围、使用用途、用户权利及隐私保护承诺。</p><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>《平台隐私政策及个人资料收集声明》适用于长桥缔约方通过其运营的平台（包括移动端、桌面端、Web 端等）为用户提供的服务。</p><p>长桥致力于根据所在地个人信息保护、隐私保护相关法律法规保护用户个人信息，仅收集个人信息作合法且相关的用途。</p><h2 id="个人资料定义" tabindex="-1">个人资料定义 <a class="header-anchor" href="#个人资料定义" aria-label="Permalink to &quot;个人资料定义&quot;">​</a></h2><p>个人资料是指同时满足以下条件的信息：</p><ul><li>直接或间接与一名在世的个人有关</li><li>从该资料可直接或间接确定个人身份</li><li>该资料的存在形式可予以查阅及处理</li></ul><h2 id="信息收集与使用" tabindex="-1">信息收集与使用 <a class="header-anchor" href="#信息收集与使用" aria-label="Permalink to &quot;信息收集与使用&quot;">​</a></h2><p>长桥仅收集提供服务所必需的个人信息，并会采取一切实际可行方法确保信息准确无误。具体收集内容详见 App 内《个人信息收集清单》。</p><p>如某项服务有单独的隐私政策或条款，该服务的隐私政策将优先适用。</p><h2 id="用户权利" tabindex="-1">用户权利 <a class="header-anchor" href="#用户权利" aria-label="Permalink to &quot;用户权利&quot;">​</a></h2><p>用户有权查阅、更正、删除个人信息，以及行使相关法律法规赋予的其他权利。具体操作方式请参考 App 内相关设置或联系客服。</p><h2 id="中国大陆用户" tabindex="-1">中国大陆用户 <a class="header-anchor" href="#中国大陆用户" aria-label="Permalink to &quot;中国大陆用户&quot;">​</a></h2><p>中国大陆地区用户除适用本政策全部内容外，还应确认并同意专门针对中国大陆地区用户的特别政策声明。</p><h2 id="查看完整政策" tabindex="-1">查看完整政策 <a class="header-anchor" href="#查看完整政策" aria-label="Permalink to &quot;查看完整政策&quot;">​</a></h2><p>完整隐私政策请在长桥 App 内或官网查看。如有疑问请联系客服。</p>',17)])])}const _=e(o,[["render",l]]);export{u as __pageData,_ as default};
